import styles from "./Activity.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import { sendScore } from "../../../../../utils/score";
// import classNames from "classnames";
import { connect } from "react-redux";
import { InjectLocale } from "../../../../../decorators/locale";
import buildActions from "../../../store/actions";
import { Key } from "../../../../../../common/constants/keyboard";
import AdaHelper from "../../../../common/components/AdaHelper/AdaHelper";
import ActivityHeader from "../../../../common/components/ActivityHeader/ActivityHeader";
import { isMobile } from "../../../../../../common/constants/user-agent";
import MobileView from "../../MobileView/MobileView";
import DesktopView from "../../DesktopView/DesktopView";
import Controls from "../../common/Controls/Controls";
import { FeedbackSoundManager } from "../../../../../utils/sound";

@connect(
  state => ({
    ...state,
    activityId: state.id,
    activityType: state.type,
    activityName: state.name,
    finalResponse: "Completed!"
  }),
  buildActions
)
@InjectLocale("Activity")
class Activity extends PureComponent {
  static propTypes = {
    activityId: PropTypes.number.isRequired,
    activityType: PropTypes.string.isRequired,
    activityName: PropTypes.string.isRequired,
    activityAlign: PropTypes.object,
    studentInstruction: PropTypes.string
  };

  state = {
    disablePreview: false,
    displayedScore: 0,
    completedItems: 0,
    complete: false,
    ariaText: ""
  };
  errors = [];
  onActivityKeyDown = e => {
    switch (e.keyCode) {
      case Key.S: {
        if (e.altKey) {
          this.completeActivity();
        }
        break;
      }
      case Key.R: {
        if (e.altKey) {
          this.restart();
        }
        break;
      }
      default:
    }
  };

  static isValueNotEmpty(item) {
    return (
      (typeof item.value === "object" && item.value !== null && item.value.url !== "") ||
      (typeof item.value !== "object" && item.value !== "")
    );
  }

  static getFilteredItems(arr) {
    return arr.filter(
      el =>
        (typeof el.item.value === "object" && el.item.value !== null && el.item.value.url !== "") ||
        (typeof el.item.value !== "object" && el.item.value !== "")
    );
  }

  componentDidMount() {
    const { activityId, activityType } = this.props;
    const activityData = JSON.parse(sessionStorage.getItem(`${activityType}-${activityId}`));
    if (
      activityData &&
      activityData.hasOwnProperty("pointsEarned") &&
      activityData.hasOwnProperty("isRestart")
    ) {
      if (activityData.isRestart === false) {
        this.setState(
          {
            displayedScore: activityData.pointsEarned,
            complete: true
          },
          this.viewRef.completeActivity
        );
      }
    }
  }

  handleIncorrectDrop(dragIndex) {
    const { playFeedbackSounds } = this.props;
    this.errors[dragIndex]++;
    if (playFeedbackSounds) {
      FeedbackSoundManager.playWrong();
    }
    this.setState({
      ariaText: this.locale.correct
    });
  }

  handleCorrectDrop(dragIndex) {
    const { activityId, activityType, score, items, playFeedbackSounds } = this.props,
      { errors } = this,
      oneItemScore = score / Activity.getFilteredItems(items).length;
    let { displayedScore, completedItems } = this.state;

    if (errors[dragIndex] > 0) {
      displayedScore += 0;
    } else {
      displayedScore += oneItemScore;
    }
    if (completedItems + 1 === Activity.getFilteredItems(items).length) {
      sendScore({
        id: activityId,
        type: activityType,
        pointsEarned: displayedScore,
        maxValue: score,
        isRestart: false
      });
    }
    if (playFeedbackSounds) {
      FeedbackSoundManager.playCorrect();
    }

    this.setState({
      displayedScore: displayedScore,
      completedItems: completedItems + 1,
      ariaText: this.locale.correct,
      complete: completedItems + 1 === Activity.getFilteredItems(items).length
    });
  }

  restart() {
    const { activityId, activityType, score } = this.props;

    sendScore({
      id: activityId,
      type: activityType,
      pointsEarned: 0,
      maxValue: score,
      isRestart: true
    });

    this.viewRef.restartActivity();
    this.errors = [];
    this.setState({
      displayedScore: 0,
      completedItems: 0,
      complete: false
    });
  }

  completeActivity() {
    const { activityId, activityType, score, items } = this.props,
      { displayedScore } = this.state;
    this.viewRef.completeActivity();
    sendScore({
      id: activityId,
      type: activityType,
      pointsEarned: displayedScore,
      maxValue: score,
      isRestart: false
    });

    this.setState({
      completedItems: Activity.getFilteredItems(items).length,
      complete: true
    });
  }

  announceFlip() {
    this.setState({
      ariaText: this.locale.flip
    });
  }

  render() {
    const {
        studentInstruction,
        activityName,
        activityId,
        showRestart,
        score,
        items,
        finalResponse
      } = this.props,
      playerId = styles.player + activityId,
      { ariaText, displayedScore, complete } = this.state,
      commonProps = {
        ...this.props,
        playerSelector: "#" + playerId,
        handleCorrectDrop: this.handleCorrectDrop.bind(this),
        handleIncorrectDrop: this.handleIncorrectDrop.bind(this),
        announceFlip: this.announceFlip.bind(this),
        ref: el => {
          this.viewRef = el;
        }
      };

    if (this.errors.length === 0) {
      for (let i = 0; i < items.length; i++) {
        this.errors[i] = 0;
      }
    }

    return (
      <section
        role="application"
        tabIndex="0"
        className={styles.container}
        onKeyDown={this.onActivityKeyDown}
      >
        <AdaHelper ariaText={ariaText} />
        <ActivityHeader activityName={activityName} studentInstruction={studentInstruction} />
        <div id={playerId} className={styles.player}>
          <Controls
            completeActivity={this.completeActivity.bind(this)}
            restart={this.restart.bind(this)}
            complete={complete}
            totalScore={score}
            displayedScore={parseFloat(displayedScore.toFixed(1))}
            showRestart={showRestart}
            onButtonFocus={() => {}}
          />
          <div className={styles.response}>{complete && <span>{finalResponse}</span>}</div>
          {isMobile ? <MobileView {...commonProps} /> : <DesktopView {...commonProps} />}
        </div>
      </section>
    );
  }
}

export default Activity;
