import React, { Component } from "react";
import shuffle from "lodash/shuffle";
import MatchView from "./MatchView/MatchView";
import Activity from "../_activity/Activity/Activity";

import styles from "./MobileView.module.scss";

export default class MobileView extends Component {
  static STATUS = {
    CORRECT: "correct",
    WRONG: "wrong",
    NONE: "none"
  };

  constructor(props) {
    super(props);

    const initialStatusArray = [];
    for (let i = 0; i < props.items.length; i++) {
      initialStatusArray[i] = MobileView.STATUS.NONE;
    }

    this.selectZone = this.selectZone.bind(this);
    this.getUnmatchedItems = this.getUnmatchedItems.bind(this);
    this.showNextMainItem = this.showNextMainItem.bind(this);
    this.showNextSubItem = this.showNextSubItem.bind(this);
    this.handleAnswer = this.handleAnswer.bind(this);

    this.state = {
      status: initialStatusArray,
      mainIndex: 0,
      subIndex: 0
    };
  }

  shuffledArray = null;
  shuffledZones = null;

  restartActivity() {
    const initialStatusArray = [];
    for (let i = 0; i < this.props.items.length; i++) {
      initialStatusArray[i] = MobileView.STATUS.NONE;
    }
    this.shuffledZones = null;
    this.shuffledArray = null;
    this.setState({
      status: initialStatusArray,
      mainIndex: 0,
      subIndex: 0
    });
  }

  completeActivity() {
    const initialStatusArray = [];
    for (let i = 0; i < this.props.items.length; i++) {
      initialStatusArray[i] = MobileView.STATUS.CORRECT;
    }

    this.setState({
      status: initialStatusArray
    });
  }

  handleAnswer() {
    const { mainIndex, subIndex, status } = this.state,
      { handleCorrectDrop, handleIncorrectDrop } = this.props,
      currentDrop = this.getUnmatchedItems(this.shuffledZones)[mainIndex],
      currentDrag = this.shuffledArray[subIndex];

    if (currentDrag.id === currentDrop.id) {
      handleCorrectDrop(subIndex);
      status[subIndex] = MobileView.STATUS.CORRECT;
      this.setState({
        status: status
      });
    } else {
      handleIncorrectDrop(subIndex);
      status[subIndex] = MobileView.STATUS.WRONG;
      this.setState({
        status: status
      });
    }
  }

  getUnmatchedItems(arr) {
    const newArray = [];
    for (let i = 0; i < arr.length; i++) {
      const indexOfItem = this.shuffledArray.indexOf(arr[i]);
      if (this.state.status[indexOfItem] !== MobileView.STATUS.CORRECT) {
        newArray.push(arr[i]);
      }
    }
    return newArray;
  }

  showNextMainItem(item) {
    const { status, mainIndex, subIndex } = this.state,
      availableOptions = this.getUnmatchedItems(this.shuffledZones),
      newMainIndex =
        item === "prev"
          ? mainIndex - 1 >= 0
            ? mainIndex - 1
            : availableOptions.length - 1
          : mainIndex + 1 < availableOptions.length
          ? mainIndex + 1
          : 0;

    if (status[subIndex] === MobileView.STATUS.WRONG) {
      status[subIndex] = MobileView.STATUS.NONE;
    }
    this.setState({
      mainIndex: newMainIndex,
      status: status
    });
  }

  showNextSubItem(item) {
    const { mainIndex, status, subIndex } = this.state,
      { items } = this.props,
      currentAnswered = status[subIndex] === MobileView.STATUS.CORRECT,
      newSubIndex =
        item === "prev"
          ? subIndex - 1 >= 0
            ? subIndex - 1
            : this.shuffledArray.length - 1
          : subIndex + 1 < this.shuffledArray.length
          ? subIndex + 1
          : 0;

    let newMainIndex = -1;
    if (status[subIndex] === MobileView.STATUS.WRONG) {
      status[subIndex] = MobileView.STATUS.NONE;
    }
    if (status[newSubIndex] !== MobileView.STATUS.CORRECT) {
      newMainIndex = 0;
    } else {
      newMainIndex = this.shuffledZones.indexOf(items[newSubIndex]);
    }
    this.setState({
      mainIndex: currentAnswered
        ? newMainIndex
        : status[newSubIndex] !== MobileView.STATUS.CORRECT
        ? mainIndex
        : newMainIndex,
      subIndex: newSubIndex
    });
  }

  selectZone(index) {
    this.props.togglePreviewButton();
    this.setState({
      mainIndex: index
    });
  }

  render() {
    const { mainIndex, subIndex, status } = this.state,
      { items } = this.props;
    if (!this.shuffledArray) {
      this.shuffledArray = Activity.getFilteredItems(shuffle(items));
    }
    if (!this.shuffledZones) {
      this.shuffledZones = shuffle(items);
    }
    const unmatchedItems = this.getUnmatchedItems(this.shuffledZones);

    return (
      <div className={styles.mobile}>
        <MatchView
          makeGuess={this.handleAnswer}
          showNextMainItem={this.showNextMainItem}
          showNextSubItem={this.showNextSubItem}
          currentMainItem={
            status[subIndex] === MobileView.STATUS.CORRECT
              ? this.shuffledArray[subIndex].zone
              : unmatchedItems[mainIndex].zone
          }
          currentSubItem={this.shuffledArray[subIndex].item}
          mainStatus={status[subIndex]}
        />
      </div>
    );
  }
}
