import React, { Component } from "react";
import classNames from "classnames";

import styles from "./MatchingCard.module.scss";
import CardContent from "../CardContent/CardContent";
import { Animations } from "../../../../../../common/constants/animations";
import { isMobile } from "../../../../../../common/constants/user-agent";

export default class MatchingCard extends Component {
  constructor(props) {
    super(props);

    this.containerRef = React.createRef();

    this.flipCard = this.flipCard.bind(this);
    this.animationEndHandler = this.animationEndHandler.bind(this);
    this.mouseOverHandler = this.mouseOverHandler.bind(this);
    this.mouseOutHandler = this.mouseOutHandler.bind(this);
    this.state = {
      showZoom: false,
      showFrontSide: true,
      animationInProgress: false
    };
  }

  animationEndHandler() {
    this.setState({
      animationInProgress: false
    });
  }

  showBackSide() {
    this.setState({
      animationInProgress: true,
      showFrontSide: false
    });
  }

  flipCard() {
    const { onClick, backSide } = this.props,
      { showFrontSide, animationInProgress } = this.state;
    if (backSide && !animationInProgress) {
      if (!animationInProgress) {
        this.props.cardFlipped();
        this.setState({
          animationInProgress: true,
          showFrontSide: !showFrontSide
        });
      }
    }
    if (onClick) {
      onClick();
    }
  }

  mouseOverHandler() {
    const { animationInProgress } = this.state;
    if (!animationInProgress) {
      this.setState({
        showZoom: true
      });
    }
  }

  mouseOutHandler() {
    const { animationInProgress } = this.state;
    if (!animationInProgress) {
      this.setState({
        showZoom: false
      });
    }
  }

  render() {
    const { backSide, frontSide, fullScreen, goFull } = this.props,
      { showFrontSide, animationInProgress, showZoom } = this.state,
      desktopHandlers = isMobile
        ? {}
        : {
            onMouseOver: this.mouseOverHandler,
            onMouseOut: this.mouseOutHandler
          };

    return (
      <div
        ref={this.containerRef}
        className={classNames(
          styles.cardWrapper,
          styles.background,
          animationInProgress && Animations.FLIP_IN_Y
        )}
        onAnimationEnd={this.animationEndHandler}
        onClick={this.flipCard}
        {...desktopHandlers}
      >
        <CardContent
          zoomFocus={this.mouseOverHandler}
          zoomBlur={this.mouseOutHandler}
          showZoom={showZoom}
          goFull={goFull}
          fullScreen={fullScreen}
          content={!showFrontSide && backSide ? backSide : frontSide}
        />
      </div>
    );
  }
}
