import React, { Component } from "react";

import styles from "./MatchView.module.scss";
import Slider from "../Slider/Slider";
import MobileView from "../MobileView";

export default class MatchView extends Component {
  render() {
    const {
      currentMainItem,
      currentSubItem,
      showNextMainItem,
      showNextSubItem,
      makeGuess,
      mainStatus
    } = this.props;
    return (
      <>
        <div className={styles.matchContainer}>
          <Slider
            itemClassName={mainStatus === MobileView.STATUS.WRONG ? styles.wrongSlider : ""}
            mainClassName={mainStatus === MobileView.STATUS.CORRECT ? styles.rightSlider : ""}
            showItem={showNextSubItem}
            item={currentSubItem}
          />
          <Slider
            disabled={mainStatus === MobileView.STATUS.CORRECT}
            itemClassName={mainStatus === MobileView.STATUS.WRONG ? styles.wrongSlider : ""}
            mainClassName={mainStatus === MobileView.STATUS.CORRECT ? styles.rightSlider : ""}
            showItem={showNextMainItem}
            item={currentMainItem}
          />
        </div>
        <button
          disabled={mainStatus === MobileView.STATUS.CORRECT}
          onClick={makeGuess}
          className={styles.matchingButton}
        >
          Match
        </button>
      </>
    );
  }
}
