import React, { Component } from "react";
import shuffle from "lodash/shuffle";
import classNames from "classnames";
import DragAndDrop from "../../../_universalDND/DragAndDrop";
import Activity from "../_activity/Activity/Activity";
import styles from "./DesktopView.module.scss";
import MatchingCard from "../common/MatchingCard/MatchingCard";
import { Key } from "../../../../../common/constants/keyboard";
import { trapTabKey } from "../../../../utils/accessibility";

export default class DesktopView extends Component {
  constructor(props) {
    super(props);

    this.handleDrop = this.handleDrop.bind(this);
    this.dndRef = React.createRef();

    this.goFull = this.goFull.bind(this);
    this.handleKeydown = this.handleKeydown.bind(this);
    this.zoomOut = this.zoomOut.bind(this);
    this.onDropKeyDown = this.onDropKeyDown.bind(this);
    this.onViewKeyDown = this.onViewKeyDown.bind(this);
    this.onViewFocus = this.onViewFocus.bind(this);
    this.completeActivity = this.completeActivity.bind(this);
    this.state = {
      fullScreen: -1,
      focusLoop: true
    };
  }

  dragArray = [];
  filledDropArray = [];
  dropCardRefs = [];
  shuffledArray = null;
  shuffledZones = null;

  componentDidMount() {
    document.addEventListener("keydown", this.handleKeydown);
  }

  componentWillUnmount() {
    document.removeEventListener("keydown", this.handleKeydown);
  }

  handleKeydown(e) {
    switch (e.keyCode) {
      case Key.ESC: {
        const { fullScreen } = this.state;
        if (fullScreen !== -1) {
          this.setState({
            fullScreen: -1
          });
        } else {
          this.dndRef.current.moveToInitialPosition();
        }
        break;
      }
      default:
    }
  }

  onViewFocus(e) {
    if (!this.refs.viewBody.contains(e.target) && !this.state.focusLoop) {
      this.setState({
        focusLoop: true
      });
    }
  }

  onViewKeyDown(e) {
    if (e.keyCode === Key.TAB && this.state.focusLoop) {
      trapTabKey(e);
    } else if (e.altKey && e.keyCode === Key.Q) {
      this.setState({
        focusLoop: false
      });
    }
  }

  onDropKeyDown(dropIndex, e) {
    if (this.filledDropArray.indexOf(dropIndex) > -1) {
      if (e.keyCode === Key.ENTER || e.keyCode === Key.SPACEBAR) {
        e.preventDefault();
        this.props.announceFlip();
        this.dropCardRefs[dropIndex].flipCard();
      }
    }
  }

  restartActivity() {
    this.dragArray = [];
    this.filledDropArray = [];
    this.shuffledArray = null;
    this.shuffledZones = null;
    this.dndRef.current.resetDranAndDrop();
    this.setState({
      fullScreen: -1
    });
  }

  completeActivity() {
    this.dndRef.current.fillDragAndDrop();
    for (let i = 0; i < this.props.items.length; i++) {
      const itemValue = this.props.items[i].item.value;
      if (
        (typeof itemValue === "object" && itemValue !== "") ||
        (itemValue !== "object" && itemValue !== null && itemValue !== "")
      ) {
        if (this.filledDropArray.indexOf(i) < 0) {
          const dragIndex = this.dragArray.indexOf(
            this.dragArray.filter(el => el === this.props.items[i].id)[0]
          );
          this.dndRef.current.createMatch(dragIndex, i);
          this.dropCardRefs[i].showBackSide();
          this.filledDropArray.push(i);
        }
      }
    }
  }

  handleDrop(dragIndex, dropIndex) {
    const { handleCorrectDrop, handleIncorrectDrop } = this.props;

    const dragItemID = this.dragArray[dragIndex],
      dropItem = this.shuffledZones[dropIndex];

    if (!dropItem || dropItem.id !== dragItemID) {
      this.dndRef.current.moveToInitialPosition();
      handleIncorrectDrop(dragIndex);
    } else {
      this.dndRef.current.moveToDropPosition();
      this.dndRef.current.createMatch(dragIndex, dropIndex);
      this.dropCardRefs[dropIndex].showBackSide();
      this.filledDropArray.push(dropIndex);
      handleCorrectDrop(dragIndex);
    }
  }

  zoomOut() {
    this.setState({
      fullScreen: -1
    });
  }

  goFull(index) {
    this.setState({
      fullScreen: index
    });
  }

  getDragsAndDrops() {
    const { fullScreen } = this.state;
    return {
      items: this.shuffledArray.map((el, index) => {
        if (this.dragArray.indexOf(el.id) < 0) {
          this.dragArray.push(el.id);
        }
        return <MatchingCard goFull={this.goFull} key={"dragCard" + index} frontSide={el.item} />;
      }),
      targets: this.shuffledZones.map((el, index) => (
        <MatchingCard
          ref={el => {
            if (this.dropCardRefs.indexOf(el) === -1) {
              this.dropCardRefs.push(el);
            }
          }}
          cardFlipped={this.props.announceFlip}
          goFull={this.goFull}
          key={"dropCard" + index}
          fullScreen={index === fullScreen}
          backSide={this.filledDropArray.indexOf(index) > -1 && el.item}
          frontSide={el.zone}
        />
      ))
    };
  }

  render() {
    const { items, playerSelector, activityId } = this.props,
      dragContainer = styles.items + activityId,
      dropContainer = styles.targets + activityId,
      { fullScreen } = this.state;

    if (!this.shuffledArray) {
      this.shuffledArray = Activity.getFilteredItems(shuffle(items));
    }
    if (!this.shuffledZones) {
      this.shuffledZones = shuffle(items);
    }
    let targetsCountStyle = "";
    if (items.length >= 1 && items.length <= 2) {
      targetsCountStyle = styles.onetwotargets;
    } else if (items.length >= 3 && items.length <= 4) {
      targetsCountStyle = styles.threefourtargets;
    } else if (items.length >= 5 && items.length <= 6) {
      targetsCountStyle = styles.fivesixtargets;
    } else if (items.length >= 7 && items.length <= 9) {
      targetsCountStyle = styles.sevenninetargets;
    }

    return (
      <div
        className={styles.desktop}
        onKeyDown={this.onViewKeyDown}
        onFocus={this.onViewFocus}
        ref="viewBody"
      >
        <div id={dragContainer} className={styles.items} />
        <div id={dropContainer} className={classNames(styles.targets, targetsCountStyle)} />
        <DragAndDrop
          dragLabels={Activity.getFilteredItems(this.shuffledArray).map(
            el => el.item.altText || el.item.value
          )}
          dropLabels={this.shuffledZones.map(el => el.zone.altText || el.zone.value)}
          onDropKeyDown={this.onDropKeyDown}
          ref={this.dndRef}
          parentSelector={playerSelector}
          handleDrop={this.handleDrop}
          dragContainerSelector={"#" + dragContainer}
          dropContainerSelector={"#" + dropContainer}
          {...this.getDragsAndDrops()}
        />
        <div
          onClick={this.zoomOut}
          style={{ display: fullScreen !== -1 ? "flex" : "none" }}
          className={styles.zommedImage}
        >
          <img src={fullScreen} alt="" />
        </div>
      </div>
    );
  }
}
