import styles from "./Score.module.scss";
import PropTypes from "prop-types";
import React, { PureComponent } from "react";
import { InjectLocale } from "../../../../decorators/locale";
import AdaHelper from "../AdaHelper/AdaHelper";

@InjectLocale("Score")
class Score extends PureComponent {
  static propTypes = {
    displayedScore: PropTypes.number.isRequired,
    totalScore: PropTypes.number.isRequired
  };

  displayedScore = 0;
  ariaText = "";

  componentWillReceiveProps(nextProps) {
    const { totalScore, displayedScore } = nextProps;

    if (totalScore) {
      if (displayedScore !== this.displayedScore) {
        this.displayedScore = displayedScore;
        this.ariaText = `${this.locale.your_score} ${this.displayedScore} ${
          this.locale.out_of
        } ${totalScore}`;
      }
    }
  }

  render() {
    const { totalScore, complete } = this.props;

    if (totalScore) {
      return (
        <div className={styles.container}>
          <AdaHelper
            ariaText={`${this.ariaText}. ${complete ? this.locale.complete_message : ""}`}
          />
          <span className={styles.current}>{this.displayedScore}</span>
          &nbsp; / &nbsp;
          <span className={styles.total}>{totalScore}</span>
        </div>
      );
    }

    return null;
  }
}

export default Score;
