import { FOCUSABLE_ELEMENTS } from "../../common/constants/attributes";

const getFocusableChildren = node => {
  const selector = FOCUSABLE_ELEMENTS.join(",");
  const children = Array.from(node.querySelectorAll(selector));

  return children.filter(child => {
    if (child.getBBox) {
      return child.getBBox().width || child.getBBox().height;
    } else {
      return !!(child.offsetWidth || child.offsetHeight || child.getClientRects().length);
    }
  });
};

export const trapTabKey = e => {
  const focusableChildren = getFocusableChildren(e.currentTarget);

  if (focusableChildren.length) {
    const focusedItemIndex = focusableChildren.indexOf(document.activeElement);

    if (e.shiftKey && focusedItemIndex === 0) {
      focusableChildren[focusableChildren.length - 1].focus();
      e.preventDefault();
    } else if (!e.shiftKey && focusedItemIndex === focusableChildren.length - 1) {
      focusableChildren[0].focus();
      e.preventDefault();
    }
  }
};
