import React, { Component } from "react";
import classNames from "classnames";

import styles from "./Drop.module.scss";
import { Key } from "../../../../common/constants/keyboard";
import { InjectLocale } from "../../../decorators/locale";
import { Classes } from "../../../../common/constants/classes";
@InjectLocale("Drop")
class Drop extends Component {
  constructor(props) {
    super(props);

    this.containerRef = React.createRef();
    this.keyDownHandler = this.keyDownHandler.bind(this);
  }

  keyDownHandler(e) {
    const { onDropKeyDown, index } = this.props;
    switch (e.keyCode) {
      case Key.SPACEBAR:
      case Key.ENTER: {
        const { index, dropSelected } = this.props;
        e.preventDefault();
        dropSelected(index);
        break;
      }
      default:
    }
    if (onDropKeyDown) {
      onDropKeyDown(index, e);
    }
  }

  render() {
    const { children, active, disabled, focusable, ariaLabel, index } = this.props;
    const { description } = this.locale;

    return (
      <div
        aria-label={ariaLabel}
        aria-describedby={`${styles.targetWrapper}${index}__description`}
        aria-dropeffect="move"
        tabIndex={focusable ? 0 : -1}
        className={classNames(styles.targetWrapper, disabled && styles.disabled)}
        onKeyDown={this.keyDownHandler}
        ref={this.containerRef}
      >
        <span
          className={Classes.VISUALLY_HIDDEN}
          id={`${styles.targetWrapper}${index}__description`}
        >
          {!disabled ? description : this.locale.disabled}
        </span>
        {children}
        {active && <div aria-hidden={true} className={styles.activeDrop} />}
      </div>
    );
  }
}

export default Drop;
