import React, { Component } from "react";
import classNames from "classnames";

import styles from "./Drag.module.scss";
import { Key } from "../../../../common/constants/keyboard";
import { InjectLocale } from "../../../decorators/locale";
import { Classes } from "../../../../common/constants/classes";

@InjectLocale("Drag")
class Drag extends Component {
  constructor(props) {
    super(props);

    this.mouseDownHandler = this.mouseDownHandler.bind(this);
    this.keyDownHandler = this.keyDownHandler.bind(this);
  }

  mouseDownHandler(e) {
    const { mouseDown, index } = this.props;
    e.preventDefault();
    mouseDown(e, index);
  }

  keyDownHandler(e) {
    switch (e.keyCode) {
      case Key.SPACEBAR:
      case Key.ENTER: {
        const { index, dragSelected } = this.props;
        e.preventDefault();
        dragSelected(index);
        break;
      }
      default:
    }
  }

  render() {
    const {
      detached,
      transitionInProgress,
      children,
      top,
      left,
      transitionEnd,
      disabled,
      focusable,
      ariaLabel,
      grabbed,
      index
    } = this.props;
    const detachedStyleObject = {
      top: top,
      left: left
    };
    const { label, description } = this.locale;

    return (
      !disabled && (
        <>
          {detached && <div className={styles.placeholder} />}
          <div
            aria-grabbed={grabbed}
            aria-label={`${label} ${ariaLabel}`}
            aria-describedby={`${styles.drag}${index}__description`}
            tabIndex={focusable ? 0 : -1}
            onTransitionEnd={transitionEnd}
            className={classNames(
              styles.drag,
              transitionInProgress && styles.transition,
              detached && styles.dragging
            )}
            style={detached ? detachedStyleObject : null}
            onMouseDown={this.mouseDownHandler}
            onKeyDown={this.keyDownHandler}
          >
            <span id={`${styles.drag}${index}__description`} className={Classes.VISUALLY_HIDDEN}>
              {description}
            </span>
            {children}
          </div>
        </>
      )
    );
  }
}

export default Drag;
