import React, { Component } from "react";
import classNames from "classnames";

import styles from "./CardContent.module.scss";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";
import { isIE, isMobile } from "../../../../../../common/constants/user-agent";

export default class CardContent extends Component {
  MIN_FONT = 9;
  constructor(props) {
    super(props);

    this.updateValueStyle = this.updateValueStyle.bind(this);
  }

  componentDidMount() {
    this.updateValueStyle();
  }

  componentDidUpdate() {
    this.updateValueStyle();
  }

  updateValueStyle() {
    if (!this.refs.value) {
      return;
    }
    const value = this.refs.value.innerText,
      { value: label } = this.refs,
      labelValue = this.refs.value.parentNode;

    if (labelValue) {
      const { style } = label;

      if (value) {
        const valueWrapperHeight = parseFloat(getComputedStyle(labelValue).height);
        const valueWrapperWidth = parseFloat(getComputedStyle(labelValue).width);

        style.removeProperty("font-size");

        let fontSize = parseFloat(getComputedStyle(labelValue).fontSize);

        style.paddingTop = 0;
        style.paddingBottom = 0;

        while (label.scrollHeight > valueWrapperHeight && fontSize > 0) {
          style.fontSize = `${fontSize}px`;
          fontSize = fontSize - 0.5;
          if (fontSize <= this.MIN_FONT) {
            labelValue.style.setProperty("align-items", "flex-start");
            labelValue.style.setProperty("overflow-y", "hidden");
            break;
          }
        }
        this.fontSize = fontSize;

        this.top = (valueWrapperHeight - label.scrollHeight) / 2;
        this.left = (valueWrapperWidth - label.scrollWidth) / 2;
      } else {
        style.removeProperty("padding-top");
        style.removeProperty("padding-bottom");
        style.removeProperty("height");
        style.removeProperty("font-size");
      }
    }
  }

  render() {
    const { content, goFull, showZoom, zoomFocus, zoomBlur } = this.props,
      buttonId = Buttons.ZOOM_IN;
    return typeof content.value === "object" && content.value !== null ? (
      <>
        <img
          className={
            isIE
              ? content.value.width / content.value.height >= 1
                ? styles.imgWidth
                : styles.imgHeight
              : null
          }
          aria-hidden={true}
          src={content.value.url}
          alt={content.altText}
          draggable={false}
        />
        {!isMobile && (
          <div className={classNames(styles.zoomPanel, showZoom && styles.active)}>
            <Button
              id={buttonId}
              className={classNames(buttonStyles[buttonId.split("_").join("-")], styles.zoomIn)}
              onFocus={zoomFocus}
              onBlur={zoomBlur}
              onMouseDown={e => {
                e.stopPropagation();
                goFull(content.value.url);
              }}
            />
          </div>
        )}
      </>
    ) : (
      <p ref="value" aria-hidden={true} className={styles.centeredParagraph}>
        {content.value}
      </p>
    );
  }
}
