import React, { Component } from "react";
import ReactDOM from "react-dom";
import Drag from "./Drag/Drag";
import Drop from "./Drop/Drop";

export default class DrapAndDrop extends Component {
  constructor(props) {
    super(props);

    this.mouseMoveHandler = this.mouseMoveHandler.bind(this);
    this.mouseDownHandler = this.mouseDownHandler.bind(this);
    this.mouseUpHandler = this.mouseUpHandler.bind(this);
    this.transitionEndHandler = this.transitionEndHandler.bind(this);
    this.findDrop = this.findDrop.bind(this);
    this.dragSelected = this.dragSelected.bind(this);
    this.dropSelected = this.dropSelected.bind(this);
    this.updateValueStyle = this.updateValueStyle.bind(this);

    this.state = {
      top: 0,
      left: 0,
      keyBoardSelected: false,
      transitionInProgress: false,
      disabledDrops: [],
      disabledDrags: []
    };
  }

  dragIndex = -1;
  dropIndex = -1;
  dragToDisable = -1;
  dragWidth = 100;
  dragHeight = 80;
  initPosition = null;
  parentNode = null;
  cursorIndent = null;
  dropRefs = [];

  resetDranAndDrop() {
    this.dragIndex = -1;
    this.dropIndex = -1;
    this.dragToDisable = -1;
    this.setState({
      top: 0,
      left: 0,
      transitionInProgress: false,
      disabledDrops: [],
      disabledDrags: []
    });
  }

  fillDragAndDrop() {
    this.dragIndex = -1;
    this.dropIndex = -1;
    this.dragToDisable = -1;
    const filledArray = [];
    for (let i = 0; i < this.props.items.length; i++) {
      filledArray.push(i);
    }
    this.setState({
      top: 0,
      left: 0,
      transitionInProgress: false,
      disabledDrops: filledArray,
      disabledDrags: filledArray
    });
  }

  createMatch(dragIndex, dropIndex) {
    const { disabledDrops } = this.state;

    if (disabledDrops.indexOf(dropIndex) < 0) {
      disabledDrops.push(dropIndex);
    }

    this.dragToDisable = dragIndex;
    this.setState({
      disabledDrops: disabledDrops
    });
  }

  updateValueStyle() {
    const { dragContainer: labelValue, value: label } = this.refs;
    const value = label.innerText;

    if (labelValue) {
      const { style } = label;

      if (value) {
        const valueWrapperHeight = parseFloat(getComputedStyle(labelValue).height);
        const valueWrapperWidth = parseFloat(getComputedStyle(labelValue).width);

        style.removeProperty("font-size");

        let fontSize = parseFloat(getComputedStyle(labelValue).fontSize);

        style.paddingTop = 0;
        style.paddingBottom = 0;

        while (label.scrollHeight > valueWrapperHeight && fontSize > 0) {
          style.fontSize = `${fontSize}px`;
          fontSize = fontSize - 0.5;
        }
        this.fontSize = fontSize;

        this.top = (valueWrapperHeight - label.scrollHeight) / 2;
        this.left = (valueWrapperWidth - label.scrollWidth) / 2;
      } else {
        style.removeProperty("padding-top");
        style.removeProperty("padding-bottom");
        style.removeProperty("height");
        style.removeProperty("font-size");
      }
    }
  }

  componentDidMount() {
    const { parentSelector } = this.props;
    this.parentNode = document.querySelector(parentSelector);
    this.forceUpdate();
  }

  mouseMoveHandler(e) {
    const { transitionInProgress, keyBoardSelected } = this.state;
    if (keyBoardSelected) return;
    if (this.dragIndex > -1 && !transitionInProgress) {
      this.dropIndex = this.findDrop(e);

      const parentPos = this.parentNode.getBoundingClientRect();
      let top = e.clientY - parentPos.top - this.cursorIndent.top,
        left = e.clientX - parentPos.left - this.cursorIndent.left;

      if (parentPos.width - left > parentPos.width) {
        left = 0;
      } else if (parentPos.width - left < this.dragWidth) {
        left = parentPos.width - this.dragWidth;
      }

      if (parentPos.height - top > parentPos.height) {
        top = 0;
      } else if (parentPos.height - top < this.dragHeight) {
        top = parentPos.height - this.dragHeight;
      }

      this.setState({
        top: top,
        left: left
      });
    }
  }

  mouseDownHandler(e, index) {
    const { keyBoardSelected } = this.state;
    if (keyBoardSelected) return;
    if (this.dragIndex === -1) {
      this.dragIndex = index;
      this.initPosition = e.currentTarget.getBoundingClientRect();
      document.addEventListener("mousemove", this.mouseMoveHandler);
      document.addEventListener("mouseup", this.mouseUpHandler);
      this.cursorIndent = {
        top: e.clientY - this.initPosition.top,
        left: e.clientX - this.initPosition.left
      };
    }
  }

  mouseUpHandler() {
    const { keyBoardSelected } = this.state;
    if (keyBoardSelected) return;
    if (this.dragIndex === -1) {
      return;
    }
    const { handleDrop } = this.props;
    handleDrop(this.dragIndex, this.dropIndex);
    document.removeEventListener("mousemove", this.mouseMoveHandler);
    document.removeEventListener("mouseup", this.mouseUpHandler);
  }

  dragSelected(index) {
    if (this.dragIndex === -1) {
      this.dragIndex = index;
      this.setState({
        keyBoardSelected: true
      });
    }
  }

  dropSelected(index) {
    if (this.dragIndex === -1) {
      return;
    }
    const { handleDrop } = this.props;
    handleDrop(this.dragIndex, index);
  }

  findDrop(e) {
    let dropIndex = -1;
    for (let i = 0; i < this.dropRefs.length; i++) {
      if (this.dropRefs[i]) {
        const dropRect = this.dropRefs[i].containerRef.current.getBoundingClientRect();
        if (
          e.clientY > dropRect.top &&
          e.clientY < dropRect.top + dropRect.height &&
          e.clientX > dropRect.left &&
          e.clientX < dropRect.left + dropRect.width
        ) {
          dropIndex = i;
          break;
        }
      }
    }
    return dropIndex;
  }

  moveToInitialPosition() {
    const { keyBoardSelected, disabledDrags } = this.state;
    if (keyBoardSelected) {
      this.dragIndex = -1;
      this.dropIndex = -1;
      this.dragToDisable = -1;
      this.setState({
        disabledDrags: disabledDrags,
        transitionInProgress: false,
        keyBoardSelected: false
      });
    } else {
      const parentPos = this.parentNode.getBoundingClientRect();
      let top = this.initPosition.top - parentPos.top,
        left = this.initPosition.left - parentPos.left;
      if (
        (this.state.top === top && this.state.left === left) ||
        (this.state.top === 0 && this.state.left === 0)
      ) {
        this.dragIndex = -1;
        this.dropIndex = -1;
        this.dragToDisable = -1;
        this.setState({
          disabledDrags: disabledDrags,
          transitionInProgress: false
        });
      } else {
        requestAnimationFrame(() => {
          this.setState({
            top: top,
            left: left,
            transitionInProgress: true
          });
        });
      }
    }
  }

  moveToDropPosition() {
    const { keyBoardSelected, disabledDrags } = this.state;
    if (keyBoardSelected) {
      if (disabledDrags.indexOf(this.dragIndex) < 0) {
        disabledDrags.push(this.dragIndex);
      }
      this.dragIndex = -1;
      this.dropIndex = -1;
      this.dragToDisable = -1;
      this.setState({
        disabledDrags: disabledDrags,
        transitionInProgress: false,
        keyBoardSelected: false
      });
    } else {
      const parentPos = this.parentNode.getBoundingClientRect();
      const dropRect = this.dropRefs[this.dropIndex].containerRef.current.getBoundingClientRect();
      let top = dropRect.top - parentPos.top + dropRect.height / 2 - this.dragHeight / 2,
        left = dropRect.left - parentPos.left + dropRect.width / 2 - this.dragWidth / 2;
      requestAnimationFrame(() => {
        this.setState({
          top: top,
          left: left,
          transitionInProgress: true
        });
      });
    }
  }

  transitionEndHandler() {
    const { transitionInProgress, disabledDrags } = this.state;
    if (transitionInProgress) {
      if (disabledDrags.indexOf(this.dragToDisable) < 0) {
        disabledDrags.push(this.dragToDisable);
      }
      this.dragIndex = -1;
      this.dropIndex = -1;
      this.dragToDisable = -1;
      this.setState({
        disabledDrags: disabledDrags,
        transitionInProgress: false
      });
    }
  }

  get drags() {
    const { dragIndex } = this;
    const { items, dragLabels } = this.props;
    const { top, left, transitionInProgress, disabledDrags, keyBoardSelected } = this.state;

    return items.map((el, index) => (
      <Drag
        ariaLabel={dragLabels[index]}
        dragSelected={this.dragSelected}
        focusable={this.dragIndex === -1}
        mouseDown={this.mouseDownHandler}
        transitionEnd={this.transitionEndHandler}
        transitionInProgress={transitionInProgress}
        index={index}
        top={top}
        left={left}
        grabbed={index === dragIndex}
        detached={index === dragIndex && !keyBoardSelected}
        key={"dragContainer" + index}
        disabled={disabledDrags.indexOf(index) > -1}
      >
        {el}
      </Drag>
    ));
  }

  get drops() {
    const { dropIndex } = this,
      { targets, dropLabels, onDropKeyDown } = this.props,
      { disabledDrops } = this.state,
      dragSelected = this.dragIndex !== -1;
    return targets.map((el, index) => (
      <Drop
        onDropKeyDown={onDropKeyDown}
        ariaLabel={dropLabels[index]}
        dropSelected={this.dropSelected}
        autoFocus={dragSelected && index === 0}
        focusable={
          (dragSelected && disabledDrops.indexOf(index) === -1) ||
          (disabledDrops.indexOf(index) > -1 && !dragSelected)
        }
        ref={el => this.dropRefs.push(el)}
        active={dropIndex === index}
        key={"dropContainer" + index}
        index={index}
        disabled={disabledDrops.indexOf(index) > -1}
      >
        {el}
      </Drop>
    ));
  }

  render() {
    const { dragContainerSelector, dropContainerSelector } = this.props;
    const dragPortal = document.querySelector(`${dragContainerSelector}`);
    const dropPortal = document.querySelector(`${dropContainerSelector}`);

    return (
      <>
        {dragPortal && ReactDOM.createPortal(this.drags, dragPortal)}
        {dropPortal && ReactDOM.createPortal(this.drops, dropPortal)}
      </>
    );
  }
}
