import React, { Component } from "react";
import classNames from "classnames";
import CardContent from "../../common/CardContent/CardContent";

import styles from "./Slider.module.scss";
import { Animations } from "../../../../../../common/constants/animations";
import Button, { buttonStyles } from "../../../../common/components/Button/Button";
import { Buttons } from "../../../../../constants/buttons";

export default class Slider extends Component {
  constructor(props) {
    super(props);

    this.onAnimationEnd = this.onAnimationEnd.bind(this);
    this.onTouchStart = this.onTouchStart.bind(this);
    this.onTouchEnd = this.onTouchEnd.bind(this);
    this.showItem = this.showItem.bind(this);

    this.state = {
      animationInProgress: false
    };
  }

  initTouchPosition = null;
  animation = "";

  onAnimationEnd() {
    this.refs.contentContainer.classList.add("animation");
    this.animation = "";
    this.setState({
      animationInProgress: false
    });
  }

  onTouchStart(e) {
    if (e.changedTouches.length === 1) {
      this.initTouchPosition = e.changedTouches[0].clientX;
      document.addEventListener("touchend", this.onTouchEnd);
    }
  }

  onTouchEnd(e) {
    if (e.changedTouches.length === 1) {
      const xDiff = this.initTouchPosition - e.changedTouches[0].clientX;
      if (Math.abs(xDiff) > 10) {
        if (xDiff < 0) {
          this.showItem("prev", Animations.BOUNCE_IN_LEFT);
        } else {
          this.showItem("next", Animations.BOUNCE_IN_RIGHT);
        }
      }
      document.removeEventListener("touchend", this.onTouchEnd);
      this.initTouchPosition = null;
    }
  }

  showItem(direction, animation) {
    const { animationInProgress } = this.state;
    if (!animationInProgress) {
      this.animation = animation;
      this.props.showItem(direction);
      this.setState({
        animationInProgress: true
      });
    }
  }

  render() {
    const { mainClassName, itemClassName, item, disabled } = this.props,
      touchHandlersObject = !disabled
        ? {
            onTouchStart: this.onTouchStart
          }
        : {};
    return (
      <div {...touchHandlersObject} className={classNames(styles.slider, mainClassName)}>
        <div
          onAnimationEnd={this.onAnimationEnd}
          ref="contentContainer"
          className={classNames(
            styles.contentContainer,
            !(item.value instanceof Object) && styles.textContainer,
            itemClassName,
            this.animation
          )}
        >
          <CardContent content={item} />
        </div>
        {!disabled && (
          <Button
            onClick={() => this.showItem("prev", Animations.BOUNCE_IN_LEFT)}
            id={Buttons.PREV}
            className={classNames(buttonStyles.prev, styles.navButton, styles.buttonPrev)}
          />
        )}
        {!disabled && (
          <Button
            onClick={() => this.showItem("next", Animations.BOUNCE_IN_RIGHT)}
            id={Buttons.NEXT}
            className={classNames(buttonStyles.next, styles.navButton, styles.buttonNext)}
          />
        )}
      </div>
    );
  }
}
