import styles from "./List.module.scss";
import React, { PureComponent } from "react";
import PropTypes from "prop-types";
import classNames from "classnames";

export { styles as listStyles };

export default class List extends PureComponent {
  static propTypes = {
    items: PropTypes.array.isRequired,
    className: PropTypes.string,
    onKeyDown: PropTypes.func.isRequired
  };

  getListItem(item, index) {
    const { onKeyDown } = this.props;
    const keyClass = item.key ? styles.key : styles.code;
    const keyValue = item.key ? item.key : item.code;

    return (
      <li
        key={index}
        tabIndex="0"
        aria-label={item.description}
        className={styles.item}
        onKeyDown={e => {
          onKeyDown(index, e);
        }}
      >
        <span className={styles.action}>{item.action}</span>
        <span className={keyClass}>{keyValue}</span>
      </li>
    );
  }

  render() {
    const { className, items } = this.props;

    return (
      <ul className={classNames(styles.container, className)}>
        {items.map((item, index) => this.getListItem(item, index))}
      </ul>
    );
  }
}
